import { useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Coins, Flame, Gift, Check } from "lucide-react";
import { toast } from "sonner";

import { tr } from "@/i18n";
export function DailyBonusCard({ profile }: { profile: any }) {
  const qc = useQueryClient();
  const [loading, setLoading] = useState(false);
  const today = new Date().toISOString().slice(0, 10);
  const claimed = profile?.last_login_bonus_date === today;
  const streak = profile?.streak_days ?? 0;
  const bonus = 5 + Math.min(streak, 30) * 2;

  async function claim() {
    setLoading(true);
    try {
      const { data, error } = await supabase.rpc("claim_daily_bonus");
      if (error) throw error;
      const res = data as any;
      if (res?.ok) toast.success(`รับโบนัส ${res.gold} ทอง! 🪙`);
      else toast.info(res?.message ?? tr("เคลมไปแล้ว"));
      qc.invalidateQueries({ queryKey: ["profile"] });
    } catch (e: any) {
      toast.error(e.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <Card className="border-primary/30 bg-gradient-to-br from-primary/5 to-transparent">
      <CardContent className="p-5 flex items-center justify-between gap-4 flex-wrap">
        <div className="flex items-center gap-3">
          <div className="size-12 rounded-xl bg-primary/15 grid place-items-center">
            <Gift className="size-6 text-primary" />
          </div>
          <div>
            <p className="font-display text-lg">{tr("โบนัสประจำวัน")}</p>
            <p className="text-sm text-muted-foreground flex items-center gap-2">
              <Flame className="size-3.5 text-orange-500" /> สตรีค {streak} วัน •
              <Coins className="size-3.5 text-amber-500" /> รับ {bonus} ทอง
            </p>
          </div>
        </div>
        <Button onClick={claim} disabled={claimed || loading} size="sm">
          {claimed ? (
            <>
              <Check className="size-4 mr-1" />
              {tr("รับแล้ววันนี้")}
            </>
          ) : (
            `รับ +${bonus}`
          )}
        </Button>
      </CardContent>
    </Card>
  );
}

import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";
import { requireSupabaseAuth } from "@/integrations/supabase/auth-middleware";

async function assertAdmin(ctx: { supabase: any; userId: string }) {
  const { data: roleRow } = await ctx.supabase
    .from("user_roles")
    .select("role")
    .eq("user_id", ctx.userId)
    .eq("role", "admin")
    .maybeSingle();
  if (!roleRow) throw new Error("เฉพาะ admin เท่านั้น");
}

export const listAuthUsers = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .handler(async ({ context }) => {
    await assertAdmin(context);
    const { supabaseAdmin } = await import("@/integrations/supabase/client.server");
    const users: {
      id: string;
      email: string | null;
      student_id: string | null;
      display_name: string | null;
      created_at: string;
      last_sign_in_at: string | null;
    }[] = [];
    for (let page = 1; page <= 20; page++) {
      const { data, error } = await supabaseAdmin.auth.admin.listUsers({ page, perPage: 200 });
      if (error) throw new Error(error.message);
      for (const u of data.users) {
        users.push({
          id: u.id,
          email: u.email ?? null,
          student_id: (u.user_metadata as any)?.student_id ?? null,
          display_name: (u.user_metadata as any)?.display_name ?? null,
          created_at: u.created_at,
          last_sign_in_at: u.last_sign_in_at ?? null,
        });
      }
      if (data.users.length < 200) break;
    }
    return { users };
  });

const ResetSchema = z.object({
  userId: z.string().uuid(),
  password: z.string().min(6).max(128),
});

export const adminResetPassword = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((data: unknown) => ResetSchema.parse(data))
  .handler(async ({ data, context }) => {
    await assertAdmin(context);
    const { supabaseAdmin } = await import("@/integrations/supabase/client.server");
    const { error } = await supabaseAdmin.auth.admin.updateUserById(data.userId, {
      password: data.password,
      email_confirm: true,
    });
    if (error) throw new Error(error.message);
    return { ok: true };
  });

const DeleteSchema = z.object({ userId: z.string().uuid() });

export const adminDeleteUser = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((data: unknown) => DeleteSchema.parse(data))
  .handler(async ({ data, context }) => {
    await assertAdmin(context);
    if (data.userId === context.userId) throw new Error("ลบบัญชีตัวเองไม่ได้");
    const { supabaseAdmin } = await import("@/integrations/supabase/client.server");
    const { error } = await supabaseAdmin.auth.admin.deleteUser(data.userId);
    if (error) throw new Error(error.message);
    return { ok: true };
  });

import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";
import { requireSupabaseAuth } from "@/integrations/supabase/auth-middleware";

function csvEscape(v: unknown): string {
  if (v === null || v === undefined) return "";
  const s = String(v);
  if (/[",\n\r]/.test(s)) return `"${s.replace(/"/g, '""')}"`;
  return s;
}

function toCsv(rows: (string | number | null | undefined)[][]): string {
  // Prepend BOM so Excel reads UTF-8 (Thai) correctly
  return "\uFEFF" + rows.map((r) => r.map(csvEscape).join(",")).join("\n");
}

async function assertClassroomOwner(supabase: any, classroomId: string, userId: string) {
  const { data: cls, error } = await supabase
    .from("classrooms")
    .select("id, name, owner_id")
    .eq("id", classroomId)
    .maybeSingle();
  if (error) throw new Error(error.message);
  if (!cls) throw new Error("ไม่พบห้องเรียน");
  if (cls.owner_id !== userId) {
    const { data: roleRow } = await supabase
      .from("user_roles")
      .select("role")
      .eq("user_id", userId)
      .eq("role", "admin")
      .maybeSingle();
    if (!roleRow) throw new Error("เฉพาะเจ้าของห้องหรือ admin เท่านั้น");
  }
  return cls as { id: string; name: string; owner_id: string };
}

export const exportGradebook = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((input: { classroomId: string }) =>
    z.object({ classroomId: z.string().uuid() }).parse(input),
  )
  .handler(async ({ data, context }) => {
    const { supabase, userId } = context;
    const cls = await assertClassroomOwner(supabase, data.classroomId, userId);

    const [{ data: members }, { data: assignments }] = await Promise.all([
      supabase.from("classroom_members").select("user_id").eq("classroom_id", data.classroomId),
      supabase
        .from("assignments")
        .select("id, title, max_score, due_date, late_penalty_percent")
        .eq("classroom_id", data.classroomId)
        .order("created_at", { ascending: true }),
    ]);

    const memberIds: string[] = (members ?? []).map((m: any) => m.user_id);
    const assignmentList: any[] = assignments ?? [];

    const [{ data: profiles }, { data: submissions }] = await Promise.all([
      memberIds.length
        ? supabase.from("profiles").select("id, display_name").in("id", memberIds)
        : Promise.resolve({ data: [] as any[] }),
      assignmentList.length
        ? supabase
            .from("submissions")
            .select("assignment_id, user_id, score, is_late")
            .in(
              "assignment_id",
              assignmentList.map((a) => a.id),
            )
        : Promise.resolve({ data: [] as any[] }),
    ]);

    const nameById = new Map<string, string>(
      (profiles ?? []).map((p: any) => [p.id, p.display_name ?? p.id.slice(0, 8)]),
    );
    const subByKey = new Map<string, { score: number | null; is_late: boolean }>();
    for (const s of submissions ?? []) {
      subByKey.set(`${s.assignment_id}:${s.user_id}`, {
        score: s.score,
        is_late: !!s.is_late,
      });
    }

    const header: (string | number)[] = ["ชื่อนักเรียน", "user_id"];
    for (const a of assignmentList) header.push(`${a.title} (/${a.max_score})`);
    header.push("รวม", "เต็ม", "ร้อยละ");

    const rows: (string | number | null | undefined)[][] = [header];
    for (const uid of memberIds) {
      const row: (string | number | null | undefined)[] = [nameById.get(uid) ?? "", uid];
      let total = 0;
      let max = 0;
      for (const a of assignmentList) {
        const s = subByKey.get(`${a.id}:${uid}`);
        max += a.max_score ?? 0;
        if (!s || s.score === null || s.score === undefined) {
          row.push("");
        } else {
          let score = s.score;
          if (s.is_late && a.late_penalty_percent > 0) {
            score = Math.max(0, Math.round(score * (1 - a.late_penalty_percent / 100)));
          }
          total += score;
          row.push(score);
        }
      }
      row.push(total, max, max > 0 ? Math.round((total / max) * 10000) / 100 : 0);
      rows.push(row);
    }

    return {
      filename: `gradebook_${cls.name.replace(/[^a-zA-Z0-9ก-๙]/g, "_")}_${new Date().toISOString().slice(0, 10)}.csv`,
      csv: toCsv(rows),
    };
  });

export const exportAttendance = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((input: { classroomId: string }) =>
    z.object({ classroomId: z.string().uuid() }).parse(input),
  )
  .handler(async ({ data, context }) => {
    const { supabase, userId } = context;
    const cls = await assertClassroomOwner(supabase, data.classroomId, userId);

    const [{ data: members }, { data: sessions }] = await Promise.all([
      supabase.from("classroom_members").select("user_id").eq("classroom_id", data.classroomId),
      supabase
        .from("attendance_sessions")
        .select("id, title, session_date")
        .eq("classroom_id", data.classroomId)
        .order("session_date", { ascending: true }),
    ]);

    const memberIds: string[] = (members ?? []).map((m: any) => m.user_id);
    const sessionList: any[] = sessions ?? [];

    const [{ data: profiles }, { data: records }] = await Promise.all([
      memberIds.length
        ? supabase.from("profiles").select("id, display_name").in("id", memberIds)
        : Promise.resolve({ data: [] as any[] }),
      sessionList.length
        ? supabase
            .from("attendance_records")
            .select("session_id, user_id, status")
            .in(
              "session_id",
              sessionList.map((s) => s.id),
            )
        : Promise.resolve({ data: [] as any[] }),
    ]);

    const nameById = new Map<string, string>(
      (profiles ?? []).map((p: any) => [p.id, p.display_name ?? p.id.slice(0, 8)]),
    );
    const recByKey = new Map<string, string>();
    for (const r of records ?? []) recByKey.set(`${r.session_id}:${r.user_id}`, r.status);

    const statusTh: Record<string, string> = {
      present: "มา",
      absent: "ขาด",
      late: "สาย",
      excused: "ลา",
    };

    const header: (string | number)[] = ["ชื่อนักเรียน", "user_id"];
    for (const s of sessionList) header.push(`${s.session_date} ${s.title}`);
    header.push("มา", "สาย", "ลา", "ขาด", "ร้อยละการเข้า");

    const rows: (string | number | null | undefined)[][] = [header];
    for (const uid of memberIds) {
      const row: (string | number | null | undefined)[] = [nameById.get(uid) ?? "", uid];
      let present = 0,
        late = 0,
        excused = 0,
        absent = 0;
      for (const s of sessionList) {
        const st = recByKey.get(`${s.id}:${uid}`) ?? "absent";
        row.push(statusTh[st] ?? st);
        if (st === "present") present++;
        else if (st === "late") late++;
        else if (st === "excused") excused++;
        else absent++;
      }
      const total = sessionList.length;
      const attendedPct = total > 0 ? Math.round(((present + late) / total) * 10000) / 100 : 0;
      row.push(present, late, excused, absent, attendedPct);
      rows.push(row);
    }

    return {
      filename: `attendance_${cls.name.replace(/[^a-zA-Z0-9ก-๙]/g, "_")}_${new Date().toISOString().slice(0, 10)}.csv`,
      csv: toCsv(rows),
    };
  });

import { createServerFn } from "@tanstack/react-start";
import { getRequest } from "@tanstack/react-start/server";
import { z } from "zod";
import { requireSupabaseAuth } from "@/integrations/supabase/auth-middleware";

const STUDENT_EMAIL_DOMAIN = "student.scholarhall.local";

const InputSchema = z.object({
  studentId: z
    .string()
    .min(3)
    .max(64)
    .regex(/^[a-z0-9._-]+$/, "invalid id"),
  password: z.string().min(6).max(128),
  displayName: z.string().min(1).max(120),
});

// Per-IP rate limit: at most N signup attempts per hour from a single IP.
// Prevents abuse of the public createStudentAccount endpoint which uses the
// service role to create users (bypassing Supabase's per-project signup quotas).
const MAX_SIGNUPS_PER_IP_PER_HOUR = 200;

function getClientIp(): string {
  try {
    const req = getRequest();
    const h = req.headers;
    return (
      h.get("cf-connecting-ip") ||
      h.get("x-real-ip") ||
      h.get("x-forwarded-for")?.split(",")[0]?.trim() ||
      "unknown"
    );
  } catch {
    return "unknown";
  }
}

async function enforceSignupRateLimit(ip: string) {
  const { supabaseAdmin } = await import("@/integrations/supabase/client.server");
  const sinceIso = new Date(Date.now() - 60 * 60 * 1000).toISOString();
  const { count, error: countErr } = await (supabaseAdmin as any)
    .from("signup_rate_limit")
    .select("id", { count: "exact", head: true })
    .eq("ip", ip)
    .gte("created_at", sinceIso);
  if (countErr) throw new Error("rate limit check failed");
  if ((count ?? 0) >= MAX_SIGNUPS_PER_IP_PER_HOUR) {
    throw new Error("มีการสมัครจาก IP นี้มากเกินไป กรุณาลองใหม่ภายหลัง");
  }
  await (supabaseAdmin as any).from("signup_rate_limit").insert({ ip });
}

async function createOne(
  input: z.infer<typeof InputSchema>,
  opts: { allowReset?: boolean } = {},
): Promise<{ userId?: string; reset?: boolean }> {
  const { supabaseAdmin } = await import("@/integrations/supabase/client.server");
  const email = `${input.studentId}@${STUDENT_EMAIL_DOMAIN}`;
  const { data: created, error } = await supabaseAdmin.auth.admin.createUser({
    email,
    password: input.password,
    email_confirm: true,
    user_metadata: {
      display_name: input.displayName,
      role: "student",
      student_id: input.studentId,
    },
  });
  if (error) {
    const msg = error.message?.toLowerCase() ?? "";
    const isDup = msg.includes("already") || msg.includes("registered") || msg.includes("exists");
    if (isDup) {
      if (!opts.allowReset) throw new Error("ID นี้ถูกใช้แล้ว");
      // Idempotent (admin/bulk) path: reset password for existing student
      // so the teacher can re-issue credentials without manual recovery.
      let existingId: string | undefined;
      for (let page = 1; page <= 20 && !existingId; page++) {
        const { data: list, error: listErr } = await supabaseAdmin.auth.admin.listUsers({
          page,
          perPage: 200,
        });
        if (listErr) throw new Error(listErr.message);
        const found = list.users.find((u) => u.email?.toLowerCase() === email.toLowerCase());
        if (found) existingId = found.id;
        if (list.users.length < 200) break;
      }
      if (!existingId) throw new Error("ID นี้ถูกใช้แล้ว แต่หา user ไม่เจอ");
      const { error: updErr } = await supabaseAdmin.auth.admin.updateUserById(existingId, {
        password: input.password,
        email_confirm: true,
      });
      if (updErr) throw new Error(updErr.message);
      return { userId: existingId, reset: true };
    }
    throw new Error(error.message || "สร้างบัญชีไม่สำเร็จ");
  }
  return { userId: created.user?.id };
}

export const createStudentAccount = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => InputSchema.parse(data))
  .handler(async ({ data }) => {
    // Public endpoint (used by student self-signup form). Apply per-IP
    // rate limit to prevent abuse of the service-role admin createUser call.
    const ip = getClientIp();
    await enforceSignupRateLimit(ip);
    const result = await createOne(data);
    return { ok: true, userId: result.userId };
  });

const BulkSchema = z.object({
  students: z.array(InputSchema).min(1).max(200),
});

export const bulkCreateStudents = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((data: unknown) => BulkSchema.parse(data))
  .handler(async ({ data, context }) => {
    // admin check
    const { supabase, userId } = context;
    const { data: roleRow } = await supabase
      .from("user_roles")
      .select("role")
      .eq("user_id", userId)
      .eq("role", "admin")
      .maybeSingle();
    if (!roleRow) throw new Error("เฉพาะ admin เท่านั้น");

    const results: { studentId: string; ok: boolean; reset?: boolean; error?: string }[] = [];
    for (const s of data.students) {
      try {
        const r = await createOne(s, { allowReset: true });
        results.push({ studentId: s.studentId, ok: true, reset: r.reset });
      } catch (e: any) {
        results.push({ studentId: s.studentId, ok: false, error: e.message ?? "error" });
      }
    }
    return { results };
  });

import { createFileRoute } from "@tanstack/react-router";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/use-auth";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import { Plus, Check, X, Lock } from "lucide-react";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { BookingsCalendar } from "@/components/bookings-calendar";

import { tr } from "@/i18n";
export const Route = createFileRoute("/_authenticated/bookings")({ component: BookingsPage });

function BookingsPage() {
  const { user, hasRole } = useAuth();
  const qc = useQueryClient();
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({
    room_id: "",
    purpose: "",
    starts_at: "",
    ends_at: "",
    notes: "",
  });

  const canBook = hasRole("teacher") || hasRole("admin");
  const isAdmin = hasRole("admin");

  const { data: rooms } = useQuery({
    queryKey: ["rooms"],
    queryFn: async () =>
      (await supabase.from("rooms").select("*").eq("is_active", true).order("name")).data ?? [],
  });

  const { data: bookings, refetch } = useQuery({
    queryKey: ["bookings", user?.id, isAdmin],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("bookings")
        .select("*, rooms(name, location)")
        .order("starts_at", { ascending: false });
      if (error) throw error;
      return data;
    },
    enabled: !!user,
  });

  const create = useMutation({
    mutationFn: async () => {
      if (!form.room_id || !form.purpose || !form.starts_at || !form.ends_at)
        throw new Error(tr("กรอกข้อมูลให้ครบ"));
      const startsAt = new Date(form.starts_at);
      const endsAt = new Date(form.ends_at);
      if (isNaN(startsAt.getTime()) || isNaN(endsAt.getTime()))
        throw new Error(tr("วันที่/เวลาไม่ถูกต้อง"));
      if (startsAt < new Date()) throw new Error(tr("ห้ามจองย้อนหลัง"));
      if (endsAt <= startsAt) throw new Error(tr("เวลาสิ้นสุดต้องมากกว่าเวลาเริ่ม"));
      if (endsAt.getTime() - startsAt.getTime() < 15 * 60 * 1000)
        throw new Error(tr("ระยะเวลาขั้นต่ำ 15 นาที"));
      const { error } = await supabase.from("bookings").insert({
        room_id: form.room_id,
        user_id: user!.id,
        purpose: form.purpose.trim().slice(0, 200),
        starts_at: form.starts_at,
        ends_at: form.ends_at,
        notes: form.notes ? form.notes.slice(0, 1000) : null,
      });
      if (error) {
        if (error.message?.includes("bookings_no_overlap") || error.code === "23P01") {
          throw new Error(tr("⛔ ช่วงเวลานี้ห้องถูกจองไปแล้ว กรุณาเลือกเวลาอื่น"));
        }
        throw error;
      }
    },
    onSuccess: () => {
      toast.success(tr("ส่งคำขอจองแล้ว รอแอดมินอนุมัติ"));
      setOpen(false);
      setForm({ room_id: "", purpose: "", starts_at: "", ends_at: "", notes: "" });
      qc.invalidateQueries({ queryKey: ["bookings"] });
    },
    onError: (e: Error) => toast.error(e.message),
  });

  const setStatus = useMutation({
    mutationFn: async ({
      id,
      status,
      reason,
    }: {
      id: string;
      status: "approved" | "rejected" | "pending" | "cancelled";
      reason?: string;
    }) => {
      const payload: {
        status: typeof status;
        approver_id?: string;
        approved_at?: string;
        rejection_reason?: string | null;
      } = { status };
      if (status === "approved") {
        payload.approver_id = user!.id;
        payload.approved_at = new Date().toISOString();
      }
      if (status === "rejected") {
        payload.approver_id = user!.id;
        payload.rejection_reason = reason ?? null;
      }
      const { error } = await supabase.from("bookings").update(payload).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success(tr("อัปเดตสถานะแล้ว"));
      refetch();
    },
    onError: (e: Error) => toast.error(e.message),
  });

  const [rejectFor, setRejectFor] = useState<string | null>(null);
  const [rejectReason, setRejectReason] = useState("");

  return (
    <div className="mx-auto max-w-6xl p-6 lg:p-10 space-y-6">
      <header className="flex items-end justify-between gap-4 flex-wrap">
        <div>
          <h1 className="font-display text-4xl">{tr("ห้องประชุม")}</h1>
