import { createFileRoute, Link, redirect } from "@tanstack/react-router";
import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/use-auth";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";
import { ArrowLeft, Plus, RotateCw, Sparkles, Trash2 } from "lucide-react";
import { toast } from "sonner";

import { tr } from "@/i18n";
export const Route = createFileRoute("/_authenticated/flashcards/$deckId")({
  beforeLoad: async () => {
    const { data } = await supabase.auth.getUser();
    if (!data.user) throw redirect({ to: "/login" });
  },
  component: DeckPage,
});

type Card = { id: string; front: string; back: string; idx: number };
type Deck = { id: string; title: string; description: string | null; owner_id: string };

function DeckPage() {
  const { deckId } = Route.useParams();
  const { user } = useAuth();
  const [deck, setDeck] = useState<Deck | null>(null);
  const [cards, setCards] = useState<Card[]>([]);
  const [mode, setMode] = useState<"manage" | "study">("manage");
  const [open, setOpen] = useState(false);
  const [front, setFront] = useState("");
  const [back, setBack] = useState("");
  // study
  const [pos, setPos] = useState(0);
  const [flipped, setFlipped] = useState(false);

  async function load() {
    const [d, c] = await Promise.all([
      supabase
        .from("flashcard_decks")
        .select("id,title,description,owner_id")
        .eq("id", deckId)
        .maybeSingle(),
      supabase.from("flashcards").select("id,front,back,idx").eq("deck_id", deckId).order("idx"),
    ]);
    setDeck(d.data as any);
    setCards((c.data as any) ?? []);
  }
  useEffect(() => {
    load();
  }, [deckId]);

  const isOwner = deck?.owner_id === user?.id;

  async function addCard() {
    if (!front.trim() || !back.trim()) return;
    const { error } = await supabase.from("flashcards").insert({
      deck_id: deckId,
      front: front.trim(),
      back: back.trim(),
      idx: cards.length,
    });
    if (error) return toast.error(error.message);
    setFront("");
    setBack("");
    setOpen(false);
    load();
  }

  async function delCard(id: string) {
    const { error } = await supabase.from("flashcards").delete().eq("id", id);
    if (error) return toast.error(error.message);
    load();
  }

  async function aiGenerate() {
    const topic = prompt(tr("หัวข้อ/เนื้อหาที่จะสร้างบัตรคำ (เช่น คำศัพท์อังกฤษพื้นฐาน 10 คำ)"));
    if (!topic) return;
    toast.info(tr("กำลังสร้างด้วย AI…"));
    const { data, error } = await supabase.functions.invoke("generate-quest", {
      body: { topic, mode: "flashcards", count: 10 },
    });
    if (error) return toast.error(error.message);
    const items = data?.cards || data?.questions || [];
    if (!items.length) return toast.error(tr("AI ไม่ได้ส่งบัตรคำกลับมา"));
    const rows = items
      .slice(0, 20)
      .map((it: any, i: number) => ({
        deck_id: deckId,
        front: it.front || it.question || it.term || "",
        back: it.back || it.answer || it.definition || "",
        idx: cards.length + i,
      }))
      .filter((r: any) => r.front && r.back);
    if (!rows.length) return toast.error(tr("ข้อมูลไม่สมบูรณ์"));
    const { error: e2 } = await supabase.from("flashcards").insert(rows);
    if (e2) return toast.error(e2.message);
    toast.success(`เพิ่ม ${rows.length} บัตรแล้ว`);
    load();
  }

  async function rate(ease: 1 | 2 | 3) {
    const card = cards[pos];
    if (!card || !user) return;
    const days = ease === 1 ? 1 : ease === 2 ? 3 : 7;
    const next = new Date(Date.now() + days * 86400000).toISOString();
    await supabase.from("flashcard_reviews").upsert(
      {
        user_id: user.id,
        card_id: card.id,
        ease,
        next_review_at: next,
        last_reviewed_at: new Date().toISOString(),
        review_count: 1,
      },
      { onConflict: "user_id,card_id" },
    );
    setFlipped(false);
    setPos((p) => (p + 1) % cards.length);
  }

  if (!deck) return <div className="p-6 text-muted-foreground">{tr("กำลังโหลด…")}</div>;

  return (
    <div className="p-4 md:p-6 space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div className="flex items-center gap-3">
          <Button variant="ghost" size="icon" asChild>
            <Link to="/flashcards">
              <ArrowLeft className="size-4" />
            </Link>
          </Button>
          <div>
            <h1 className="text-2xl font-display">{deck.title}</h1>
            <p className="text-sm text-muted-foreground">{cards.length} บัตร</p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button
            variant={mode === "manage" ? "default" : "outline"}
            size="sm"
            onClick={() => setMode("manage")}
          >
            {tr("จัดการ")}
          </Button>
          <Button
            variant={mode === "study" ? "default" : "outline"}
            size="sm"
            onClick={() => {
              setMode("study");
              setPos(0);
              setFlipped(false);
            }}
            disabled={!cards.length}
          >
            {tr("ทบทวน")}
          </Button>
        </div>
      </div>

      {mode === "manage" ? (
        <div className="space-y-3">
          {isOwner && (
            <div className="flex gap-2 flex-wrap">
              <Dialog open={open} onOpenChange={setOpen}>
                <DialogTrigger asChild>
                  <Button>
                    <Plus className="size-4" />
                    {tr("เพิ่มบัตร")}
                  </Button>
                </DialogTrigger>
                <DialogContent>
                  <DialogHeader>
                    <DialogTitle>{tr("เพิ่มบัตรคำ")}</DialogTitle>
                  </DialogHeader>
                  <div className="space-y-3">
                    <div>
                      <Label>{tr("หน้า (คำถาม)")}</Label>
                      <Textarea value={front} onChange={(e) => setFront(e.target.value)} />
                    </div>
                    <div>
                      <Label>{tr("หลัง (คำตอบ)")}</Label>
                      <Textarea value={back} onChange={(e) => setBack(e.target.value)} />
                    </div>
                  </div>
                  <DialogFooter>
                    <Button onClick={addCard}>{tr("เพิ่ม")}</Button>
                  </DialogFooter>
                </DialogContent>
              </Dialog>
              <Button variant="outline" onClick={aiGenerate}>
                <Sparkles className="size-4" />
                {tr("สร้างด้วย AI")}
              </Button>
            </div>
          )}
          {cards.length === 0 ? (
            <Card>
              <CardContent className="p-8 text-center text-muted-foreground">
                {tr("ยังไม่มีบัตร")}
              </CardContent>
            </Card>
          ) : (
            <div className="grid sm:grid-cols-2 gap-3">
              {cards.map((c) => (
                <Card key={c.id}>
                  <CardContent className="p-4 space-y-2">
                    <div className="font-medium">{c.front}</div>
                    <div className="text-sm text-muted-foreground border-t pt-2">{c.back}</div>
                    {isOwner && (
                      <div className="flex justify-end">
                        <Button variant="ghost" size="icon" onClick={() => delCard(c.id)}>
                          <Trash2 className="size-4" />
                        </Button>
                      </div>
                    )}
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      ) : (
        <div className="max-w-2xl mx-auto space-y-4">
          <p className="text-center text-sm text-muted-foreground">
            บัตรที่ {pos + 1} / {cards.length}
          </p>
          <Card
            className="min-h-[280px] cursor-pointer hover:border-primary/50"
            onClick={() => setFlipped((f) => !f)}
          >
            <CardContent className="p-10 grid place-items-center text-center min-h-[280px]">
              <div>
                <p className="text-xs text-muted-foreground mb-3">
                  {flipped ? tr("คำตอบ") : tr("คำถาม")}: {tr("คลิกเพื่อพลิก")}
                </p>
                <p className="text-2xl font-display">
                  {flipped ? cards[pos]?.back : cards[pos]?.front}
                </p>
              </div>
            </CardContent>
          </Card>
          {flipped ? (
            <div className="flex gap-2 justify-center">
              <Button variant="destructive" onClick={() => rate(1)}>
                {tr("ยาก (พรุ่งนี้)")}
              </Button>
              <Button variant="secondary" onClick={() => rate(2)}>
                {tr("พอใช้ (3 วัน)")}
              </Button>
              <Button onClick={() => rate(3)}>{tr("ง่าย (7 วัน)")}</Button>
            </div>
          ) : (
            <div className="flex justify-center">
              <Button variant="outline" onClick={() => setFlipped(true)}>
                <RotateCw className="size-4" />
                {tr("พลิกบัตร")}
              </Button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function Label({ children }: { children: React.ReactNode }) {
  return <label className="text-sm font-medium mb-1 block">{children}</label>;
}

import { createFileRoute } from "@tanstack/react-router";
import { useQuery } from "@tanstack/react-query";
import { useEffect, useMemo, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent } from "@/components/ui/card";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Crown, Zap, Flame, Trophy, Medal } from "lucide-react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { tr } from "@/i18n";

export const Route = createFileRoute("/_authenticated/hall-of-fame")({ component: HallOfFame });

function HallOfFame() {
  const [classroomId, setClassroomId] = useState<string>("all");

  const { data: classrooms } = useQuery({
    queryKey: ["hof-classrooms"],
    queryFn: async () =>
      (await supabase.from("classrooms").select("id, name").order("name")).data ?? [],
  });

  // ห้องเฉพาะ: ดึงจาก classroom_scores (ครูเป็นผู้ตั้ง)
  const { data: scores, refetch: refetchScores } = useQuery({
    queryKey: ["hof-scores", classroomId],
    enabled: classroomId !== "all",
    queryFn: async () => {
      const { data } = await supabase
        .from("classroom_scores")
        .select("*")
        .eq("classroom_id", classroomId);
      return data ?? [];
    },
  });

  // รวมทุกห้อง: aggregate จาก classroom_scores ทุกห้อง (ให้ตรงกับการ์ด "ดาวเด่นในห้องเรียน")
  const { data: allScores, refetch: refetchProfiles } = useQuery({
    queryKey: ["hof-all-scores"],
    enabled: classroomId === "all",
    queryFn: async () => {
      const { data: scores } = await supabase
        .from("classroom_scores")
        .select("user_id, xp, quests_completed, streak_days, perfect_scores");
      const agg = new Map<
        string,
        { xp: number; quests_completed: number; streak_days: number; perfect_scores: number }
      >();
      (scores ?? []).forEach((s: any) => {
        const cur = agg.get(s.user_id) ?? {
          xp: 0,
          quests_completed: 0,
          streak_days: 0,
          perfect_scores: 0,
        };
        agg.set(s.user_id, {
          xp: cur.xp + (s.xp ?? 0),
          quests_completed: cur.quests_completed + (s.quests_completed ?? 0),
          streak_days: Math.max(cur.streak_days, s.streak_days ?? 0),
          perfect_scores: cur.perfect_scores + (s.perfect_scores ?? 0),
        });
      });
      const ids = Array.from(agg.keys());
      if (ids.length === 0) return [] as any[];
      const { data: profs } = await supabase
        .from("profiles")
        .select("id, display_name, avatar_url, level")
        .in("id", ids);
      const pmap = new Map((profs ?? []).map((p: any) => [p.id, p]));
      return ids.map((uid) => {
        const a = agg.get(uid)!;
        const p = pmap.get(uid) as any;
        return {
          id: uid,
          display_name: p?.display_name ?? "Anonymous",
          avatar_url: p?.avatar_url,
          level: p?.level ?? 1,
          xp: a.xp,
          quests_completed: a.quests_completed,
          streak_days: a.streak_days,
          perfect_scores: a.perfect_scores,
        };
      });
    },
  });

  const userIds = useMemo(
    () => Array.from(new Set((scores ?? []).map((s: any) => s.user_id))),
    [scores],
  );

  const { data: profiles } = useQuery({
    queryKey: ["hof-profiles", userIds.join(",")],
    enabled: userIds.length > 0,
    queryFn: async () =>
      (
        await supabase
          .from("profiles")
          .select("id, display_name, avatar_url, level")
          .in("id", userIds)
      ).data ?? [],
  });

  // Realtime: subscribe ทั้ง classroom_scores และ profiles
  useEffect(() => {
    const ch = supabase
      .channel("lb-live")
      .on("postgres_changes", { event: "*", schema: "public", table: "classroom_scores" }, () => {
        refetchScores();
      })
      .on("postgres_changes", { event: "*", schema: "public", table: "profiles" }, () => {
        refetchProfiles();
      })
      .subscribe();
    return () => {
      supabase.removeChannel(ch);
    };
  }, [refetchScores, refetchProfiles]);

  const profMap = new Map((profiles ?? []).map((p: any) => [p.id, p]));

  const aggregated = useMemo(() => {
    if (classroomId === "all") {
      return (allScores ?? []).map((p: any) => ({
        user_id: p.id,
        xp: p.xp ?? 0,
        quests_completed: p.quests_completed ?? 0,
        streak_days: p.streak_days ?? 0,
        perfect_scores: p.perfect_scores ?? 0,
        display_name: p.display_name ?? "Anonymous",
        avatar_url: p.avatar_url,
        level: p.level ?? 1,
      }));
    }
    return (scores ?? []).map((s: any) => {
      const p = profMap.get(s.user_id) as any;
      return {
        user_id: s.user_id,
        xp: s.xp ?? 0,
        quests_completed: s.quests_completed ?? 0,
        streak_days: s.streak_days ?? 0,
        perfect_scores: s.perfect_scores ?? 0,
        display_name: p?.display_name ?? "Anonymous",
        avatar_url: p?.avatar_url,
        level: p?.level ?? 1,
      };
    });
  }, [classroomId, allScores, scores, profMap]);

  function rankStyle(i: number) {
    if (i === 0) return "from-yellow-400/30 to-yellow-100/10 border-yellow-500/50";
    if (i === 1) return "from-slate-300/30 to-slate-100/10 border-slate-400/50";
    if (i === 2) return "from-orange-400/30 to-orange-100/10 border-orange-500/50";
    return "";
  }

  return (
    <div className="mx-auto max-w-5xl p-6 lg:p-10 space-y-6">
      <header className="text-center space-y-2">
        <Crown className="size-12 mx-auto text-primary" />
        <h1 className="font-display text-5xl">Hall of Fame</h1>
        <p className="text-muted-foreground">
          {classroomId === "all"
            ? tr("คะแนนรวมจากโปรไฟล์ (อัปเดตเรียลไทม์เมื่อทำเควสต์/ได้ XP)")
            : tr("คะแนนจากห้องเรียน ครูเป็นผู้กำหนด")}
        </p>
      </header>

      <div className="flex justify-center">
        <Select value={classroomId} onValueChange={setClassroomId}>
          <SelectTrigger className="w-[280px]">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{tr("รวมทุกห้องเรียน")}</SelectItem>
            {classrooms?.map((c) => (
              <SelectItem key={c.id} value={c.id}>
                {c.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <Tabs defaultValue="xp">
        <TabsList>
          <TabsTrigger value="xp">
            <Zap className="size-4 mr-1" />
            XP
          </TabsTrigger>
          <TabsTrigger value="quests">
            <Trophy className="size-4 mr-1" />
            {tr("เควสต์")}
          </TabsTrigger>
          <TabsTrigger value="streak">
            <Flame className="size-4 mr-1" />
            {tr("สตรีค")}
          </TabsTrigger>
          <TabsTrigger value="perfect">
            <Medal className="size-4 mr-1" />
            Perfect
          </TabsTrigger>
        </TabsList>
        {(["xp", "quests", "streak", "perfect"] as const).map((key) => {
          const sortKey =
            key === "xp"
              ? "xp"
              : key === "quests"
                ? "quests_completed"
                : key === "streak"
                  ? "streak_days"
                  : "perfect_scores";
          const sorted = [...aggregated]
            .sort((a: any, b: any) => (b[sortKey] ?? 0) - (a[sortKey] ?? 0))
            .slice(0, 50);
          return (
            <TabsContent key={key} value={key} className="space-y-2 mt-4">
              {sorted.length === 0 && (
                <p className="text-center text-muted-foreground text-sm py-10">
                  {tr("ยังไม่มีคะแนน")}
                </p>
              )}
              {sorted.map((p: any, i: number) => (
                <Card key={p.user_id} className={`bg-gradient-to-r ${rankStyle(i)}`}>
                  <CardContent className="pt-4 flex items-center gap-4">
                    <div className="text-2xl font-display w-10 text-center">{i + 1}</div>
                    <Avatar>
                      <AvatarImage src={p.avatar_url ?? undefined} />
                      <AvatarFallback>{p.display_name?.[0] ?? "?"}</AvatarFallback>
                    </Avatar>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium truncate">{p.display_name}</p>
                    </div>
                    <div className="text-right">
                      <p className="font-display text-xl">{p[sortKey] ?? 0}</p>
                      <p className="text-xs text-muted-foreground">Lv.{p.level}</p>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </TabsContent>
          );
        })}
      </Tabs>
    </div>
  );
}

import { createFileRoute } from "@tanstack/react-router";
