    stars: 1,
    label: "VERY EASY",
    className: "bg-emerald-50 text-emerald-700 border-emerald-200",
  },
  ง่ายมาก: {
    stars: 1,
    label: "ง่ายมาก",
    className: "bg-emerald-50 text-emerald-700 border-emerald-200",
  },
  easy: {
    stars: 2,
    label: "EASY",
    className: "bg-emerald-100 text-emerald-700 border-emerald-200",
  },
  ง่าย: {
    stars: 2,
    label: "ง่าย",
    className: "bg-emerald-100 text-emerald-700 border-emerald-200",
  },
  normal: { stars: 3, label: "MEDIUM", className: "bg-amber-100 text-amber-700 border-amber-200" },
  medium: { stars: 3, label: "MEDIUM", className: "bg-amber-100 text-amber-700 border-amber-200" },
  ปานกลาง: {
    stars: 3,
    label: "ปานกลาง",
    className: "bg-amber-100 text-amber-700 border-amber-200",
  },
  hard: { stars: 4, label: "HARD", className: "bg-orange-100 text-orange-700 border-orange-200" },
  ยาก: { stars: 4, label: "ยาก", className: "bg-orange-100 text-orange-700 border-orange-200" },
  expert: { stars: 5, label: "EXPERT", className: "bg-rose-100 text-rose-700 border-rose-200" },
  ยากมาก: { stars: 5, label: "ยากมาก", className: "bg-rose-100 text-rose-700 border-rose-200" },
};

export function QuestCard({
  quest,
  attempt,
  locked,
  playerLevel,
  playerXp,
  mode = "student",
  onDone,
}: any) {
  const qc = useQueryClient();
  const meta =
    difficultyMeta[String(quest.difficulty ?? "medium").toLowerCase()] ?? difficultyMeta.medium;
  const questions = (quest.questions ?? []) as any[];
  const estMinutes = Math.max(5, questions.length * 4);

  const [expanded, setExpanded] = useState(false);
  const [answers, setAnswers] = useState<string[]>(() => questions.map(() => ""));
  const [submitting, setSubmitting] = useState(false);
  const [result, setResult] = useState<any | null>(null);

  const isTeacher = mode === "teacher";

  async function submit() {
    setSubmitting(true);
    try {
      const { data: graded, error } = await supabase.functions.invoke("grade-quest-answer", {
        body: { quest_id: quest.id, answers },
      });
      if (error) throw error;
      const { data: award, error: e2 } = await supabase.rpc("award_quest_attempt", {
        _quest_id: quest.id,
        _answers: answers,
        _score: graded.total_score,
        _max_score: graded.max_score,
        _feedback: graded.overall_feedback,
        _per_question: graded.results,
      });
      if (e2) throw e2;
      setResult({ ...graded, ...(award as any) });
      toast.success(`ได้ ${(award as any).xp_gained} XP + ${(award as any).gold_awarded} ทอง!`);
      qc.invalidateQueries({ queryKey: ["my-attempts"] });
      qc.invalidateQueries({ queryKey: ["my-dq-attempts"] });
      qc.invalidateQueries({ queryKey: ["profile"] });
      onDone?.();
    } catch (e: any) {
      toast.error(e.message ?? tr("ผิดพลาด"));
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <Card
      className={`relative overflow-hidden transition-all duration-300 ${locked ? "bg-muted/30" : "hover:shadow-md"}`}
    >
      <CardContent className="p-5 space-y-3">
        {/* Top row: difficulty + stars */}
        <div className="flex items-start justify-between gap-2">
          <Badge
            className={`uppercase tracking-wide text-[10px] font-bold border ${meta.className}`}
          >
            {locked ? (
              <>
                <Lock className="size-3 mr-1" />
                Lv.{quest.min_level}+
              </>
            ) : (
              meta.label
            )}
          </Badge>
          <div className="flex gap-0.5">
            {Array.from({ length: 5 }).map((_, i) => (
              <Star
                key={i}
                className={`size-3.5 ${i < meta.stars ? "fill-amber-400 text-amber-400" : "text-muted-foreground/30"}`}
              />
            ))}
          </div>
        </div>

        {/* Title + classroom */}
        <div className="space-y-1">
          <h3 className="font-semibold leading-tight line-clamp-2 flex items-start gap-1.5">
            {attempt && <Check className="size-4 text-green-500 shrink-0 mt-0.5" />}
            {!attempt && !locked && <Sparkles className="size-4 text-primary shrink-0 mt-0.5" />}
            <span>{quest.title}</span>
          </h3>
          {quest.classrooms?.name && (
            <p className="text-[11px] uppercase tracking-wide text-muted-foreground font-medium">
              {quest.classrooms.name}
            </p>
          )}
          <p className="text-xs text-muted-foreground">AI-generated practice quest</p>
        </div>

        {/* Stats row */}
        <div className="flex items-center justify-between gap-2 pt-1">
          <div className="flex items-center gap-3 text-xs text-muted-foreground">
            <span className="flex items-center gap-1 text-primary font-medium">
              <Zap className="size-3.5" />+{quest.max_xp_reward}
            </span>
            <span className="flex items-center gap-1 text-amber-600 font-medium">
              <Coins className="size-3.5" />+{quest.max_gold_reward}
            </span>
            <span className="flex items-center gap-1">
              <Clock className="size-3.5" />
              {estMinutes}m
            </span>
          </div>
          {isTeacher ? (
            <Button
              size="sm"
              variant="outline"
              onClick={() => setExpanded((v) => !v)}
              className="gap-1"
            >
              <Users className="size-3.5" />
              {expanded ? tr("ซ่อน") : tr("ดูคำตอบนักเรียน")}
              <ChevronDown
                className={`size-3.5 transition-transform ${expanded ? "rotate-180" : ""}`}
              />
            </Button>
          ) : locked ? (
            <Button size="sm" variant="outline" disabled className="gap-1">
              <Lock className="size-3" />
              Locked
            </Button>
          ) : attempt || result ? (
            <Button
              size="sm"
              variant="outline"
              onClick={() => setExpanded((v) => !v)}
              className="gap-1"
            >
              <Check className="size-3.5 text-green-600" />
              {expanded ? tr("ซ่อน") : tr("ดูผล")}
            </Button>
          ) : (
            <Button size="sm" onClick={() => setExpanded((v) => !v)} className="gap-1">
              {expanded ? (
                <>
                  {tr("ซ่อน")} <ChevronDown className="size-3.5 rotate-180" />
                </>
              ) : (
                <>
                  Start <ChevronRight className="size-3.5" />
                </>
              )}
            </Button>
          )}
        </div>

        {/* Attempt summary */}
        {attempt && !expanded && (
          <div className="rounded-md bg-muted/40 px-2.5 py-1.5 text-[11px] text-muted-foreground">
            {tr("คะแนน")}{" "}
            <b className="text-foreground">
              {attempt.score}/{attempt.max_score}
            </b>{" "}
            • +{attempt.xp_awarded} XP • +{attempt.gold_awarded} {tr("ทอง")}
          </div>
        )}

        {/* Locked progress hint */}
        {locked && !isTeacher && (
          <div className="rounded-md bg-muted/40 px-2.5 py-2 space-y-1">
            <Progress value={(playerLevel / (quest.min_level || 1)) * 100} className="h-1.5" />
            <p className="text-[11px] text-muted-foreground flex items-center gap-1">
              <ArrowUp className="size-3" />
              อีก {Math.max(0, quest.min_level - playerLevel)} เลเวล หรือ{" "}
              {Math.max(0, (quest.min_level - playerLevel) * 100 - (playerXp % 100))} XP
            </p>
          </div>
        )}

        {/* EXPANDED CONTENT */}
        {expanded && !locked && (
          <div className="pt-2 border-t space-y-3">
            {isTeacher ? (
              <TeacherAnswersView questId={quest.id} questions={questions} />
            ) : attempt ? (
              <AttemptResultView attempt={attempt} questions={questions} />
            ) : result ? (
              <AttemptResultView
                attempt={{
                  score: result.score,
                  max_score: result.max_score,
                  xp_awarded: result.xp_gained,
                  gold_awarded: result.gold_awarded,
                  ai_feedback: result.overall_feedback,
                  per_question: result.results,
                  answers,
                }}
                questions={questions}
              />
            ) : (
              <div className="space-y-3">
                {questions.map((q: any, i: number) => (
                  <div key={i} className="space-y-1.5">
                    <div className="flex items-start justify-between gap-2">
                      <p className="text-sm font-medium">
                        {i + 1}. {q.question}
                      </p>
                      {q.difficulty_label && (
                        <Badge variant="secondary" className="shrink-0 text-[10px]">
                          {q.difficulty_label}
                        </Badge>
                      )}
                    </div>
                    <Textarea
                      rows={2}
                      value={answers[i] ?? ""}
                      onChange={(e) => {
                        const a = [...answers];
                        a[i] = e.target.value;
                        setAnswers(a);
                      }}
                      placeholder={tr("พิมพ์คำตอบของคุณ...")}
                    />
                  </div>
                ))}
                <Button className="w-full" onClick={submit} disabled={submitting}>
                  {submitting ? (
                    <Loader2 className="size-4 mr-2 animate-spin" />
                  ) : (
                    <Trophy className="size-4 mr-2" />
                  )}
                  {tr("ส่งให้ AI ตรวจ")}
                </Button>
              </div>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

function AttemptResultView({ attempt, questions }: { attempt: any; questions: any[] }) {
  const pct = attempt.max_score ? Math.round((attempt.score / attempt.max_score) * 100) : 0;
  const tone = pct >= 80 ? "text-green-600" : pct >= 50 ? "text-amber-600" : "text-red-600";
  const per: any[] = attempt.per_question ?? [];
  const ans: string[] = attempt.answers ?? [];
  return (
    <div className="space-y-3">
      <div className="rounded-lg border bg-muted/30 p-3 space-y-1.5">
        <div className="flex items-center justify-between">
          <span className="text-sm font-medium">{tr("ความถูกต้อง")}</span>
          <span className={`text-2xl font-bold ${tone}`}>{pct}%</span>
        </div>
        <Progress value={pct} className="h-1.5" />
        <p className="text-xs text-muted-foreground">
          {tr("คะแนน")} {attempt.score}/{attempt.max_score} • +{attempt.xp_awarded} XP • +
          {attempt.gold_awarded} {tr("ทอง")}
        </p>
        {attempt.ai_feedback && (
          <p className="italic text-xs text-muted-foreground pt-1">"{attempt.ai_feedback}"</p>
        )}
      </div>
      <div className="space-y-2">
        {questions.map((q: any, i: number) => {
          const r = per[i] ?? per.find((x: any) => x.idx === i);
          return (
            <div key={i} className="text-xs rounded border p-2 space-y-1">
              <p className="font-medium">
                {i + 1}. {q.question}
              </p>
              {ans[i] && (
                <p className="text-muted-foreground">
                  {tr("คำตอบ")}: {ans[i]}
                </p>
              )}
              {r && (
                <p className="flex items-start gap-1">
                  <span>{r.correct ? "✅" : "❌"}</span>
                  <span>
                    <b>
                      {r.score}/{r.max_score}
                    </b>
                    : {r.feedback}
                  </span>
                </p>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

function TeacherAnswersView({ questId, questions }: { questId: string; questions: any[] }) {
  const { data: attempts, isLoading } = useQuery({
    queryKey: ["quest-attempts", questId],
    queryFn: async () =>
      (
        await supabase
          .from("daily_quest_attempts")
          .select("*")
          .eq("quest_id", questId)
          .order("completed_at", { ascending: false })
      ).data ?? [],
  });
  const userIds = Array.from(new Set((attempts ?? []).map((a: any) => a.user_id)));
  const { data: profiles } = useQuery({
    queryKey: ["attempt-profiles", userIds.join(",")],
    queryFn: async () =>
      (await supabase.from("profiles").select("id,display_name").in("id", userIds)).data ?? [],
    enabled: userIds.length > 0,
  });
  const nameMap = Object.fromEntries(
    (profiles ?? []).map((p: any) => [p.id, p.display_name || tr("นักเรียน")]),
  );

  if (isLoading) return <p className="text-xs text-muted-foreground">{tr("กำลังโหลด…")}</p>;
  if (!attempts || attempts.length === 0)
    return <p className="text-xs text-muted-foreground">{tr("ยังไม่มีนักเรียนทำเควสต์นี้")}</p>;

  return (
    <div className="space-y-3">
      <p className="text-xs text-muted-foreground">
        {attempts.length} {tr("คนทำแล้ว")}
      </p>
      {attempts.map((a: any) => {
        const pct = a.max_score ? Math.round((a.score / a.max_score) * 100) : 0;
        const per: any[] = a.per_question ?? [];
        const ans: string[] = a.answers ?? [];
        return (
          <details key={a.id} className="rounded border bg-muted/20 group">
            <summary className="cursor-pointer p-2.5 flex items-center justify-between gap-2 text-sm list-none">
              <span className="font-medium truncate">
                {nameMap[a.user_id] ?? a.user_id.slice(0, 8)}
              </span>
              <div className="flex items-center gap-2 shrink-0">
                <Badge
                  variant={pct >= 80 ? "default" : pct >= 50 ? "secondary" : "outline"}
                  className="text-[10px]"
                >
                  {a.score}/{a.max_score} ({pct}%)
                </Badge>
                <ChevronDown className="size-3.5 transition-transform group-open:rotate-180" />
              </div>
            </summary>
            <div className="px-2.5 pb-2.5 space-y-2">
              {a.ai_feedback && (
                <p className="italic text-xs text-muted-foreground">"{a.ai_feedback}"</p>
              )}
              {questions.map((q: any, i: number) => {
                const r = per[i] ?? per.find((x: any) => x.idx === i);
                return (
                  <div key={i} className="text-xs rounded border bg-background p-2 space-y-1">
                    <p className="font-medium">
                      {i + 1}. {q.question}
                    </p>
                    <p className="text-muted-foreground">
                      <span className="text-foreground/70">{tr("คำตอบ")}:</span> {ans[i] || "—"}
                    </p>
                    <p className="text-muted-foreground">
                      <span className="text-foreground/70">{tr("เฉลย")}:</span> {q.expected_answer}
                    </p>
                    {r && (
                      <p className="flex items-start gap-1">
                        <span>{r.correct ? "✅" : "❌"}</span>
                        <span>
                          <b>
                            {r.score}/{r.max_score}
                          </b>
                          : {r.feedback}
                        </span>
                      </p>
                    )}
                  </div>
                );
              })}
            </div>
          </details>
        );
      })}
    </div>
  );
}

import { createFileRoute, useNavigate, Link } from "@tanstack/react-router";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { useEffect, useMemo, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/use-auth";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { toast } from "sonner";
import { QRCodeSVG } from "qrcode.react";
import { Trophy, Play, ChevronRight, Check, X, Crown, Medal, Zap, Loader2 } from "lucide-react";

import { tr } from "@/i18n";
export const Route = createFileRoute("/_authenticated/quiz/$sessionId")({
  component: QuizPlayPage,
});

const OPTION_COLORS = [
  "bg-red-500 hover:bg-red-600 border-red-600",
  "bg-blue-500 hover:bg-blue-600 border-blue-600",
  "bg-amber-500 hover:bg-amber-600 border-amber-600",
  "bg-green-500 hover:bg-green-600 border-green-600",
];
const OPTION_SHAPES = ["▲", "◆", "●", "■"];

function QuizPlayPage() {
  const { sessionId } = Route.useParams();
  const { user } = useAuth();
  const qc = useQueryClient();
  const nav = useNavigate();

  const { data: session, refetch: refetchSession } = useQuery({
    queryKey: ["quiz-session", sessionId],
    queryFn: async () =>
      (await supabase.from("quiz_sessions").select("*").eq("id", sessionId).single()).data,
  });
  const { data: questions } = useQuery({
    queryKey: ["quiz-questions", sessionId],
    queryFn: async () =>
      (
        await supabase
          .from("quiz_questions_safe" as any)
          .select("*")
          .eq("session_id", sessionId)
          .order("idx")
      ).data ?? [],
  });
  const { data: participants, refetch: refetchPart } = useQuery({
    queryKey: ["quiz-participants", sessionId],
    queryFn: async () =>
      (
        await supabase
          .from("quiz_participants")
          .select("*")
          .eq("session_id", sessionId)
          .order("total_score", { ascending: false })
      ).data ?? [],
  });

  // realtime
  useEffect(() => {
    const ch = supabase
      .channel("quiz-" + sessionId)
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "quiz_sessions", filter: `id=eq.${sessionId}` },
        () => refetchSession(),
      )
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "quiz_participants",
          filter: `session_id=eq.${sessionId}`,
        },
        () => refetchPart(),
      )
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "quiz_answers",
          filter: `session_id=eq.${sessionId}`,
        },
        () => {
          qc.invalidateQueries({ queryKey: ["quiz-answers", sessionId] });
        },
      )
      .subscribe();
    return () => {
      supabase.removeChannel(ch);
    };
  }, [sessionId, refetchSession, refetchPart, qc]);

  if (!session)
    return (
      <div className="p-10 text-center">
        <Loader2 className="animate-spin mx-auto" />
      </div>
    );

  const isHost = session.host_id === user?.id;
  const currentQ = questions?.[session.current_question_idx];

  return (
    <div className="mx-auto max-w-5xl p-6 lg:p-10 space-y-6">
      <header className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <p className="text-xs uppercase tracking-widest text-muted-foreground">Live Quiz</p>
          <h1 className="font-display text-3xl">{session.title}</h1>
        </div>
        <Badge variant="outline" className="text-base font-mono px-3 py-1">
          {session.join_code}
        </Badge>
      </header>

      {session.status === "lobby" && (
        <Lobby session={session} participants={participants ?? []} isHost={isHost} />
      )}
      {(session.status === "active" || session.status === "question_revealed") && currentQ && (
        <Playing
          session={session}
          question={currentQ}
          totalQuestions={questions?.length ?? 0}
          isHost={isHost}
          userId={user!.id}
        />
      )}
      {session.status === "finished" && (
        <Finished participants={participants ?? []} isHost={isHost} sessionId={sessionId} />
      )}
    </div>
  );
}

function Lobby({ session, participants, isHost }: any) {
  const joinUrl =
    typeof window !== "undefined"
      ? `${window.location.origin}/quiz/join?code=${session.join_code}`
      : "";
  async function start() {
    const { error } = await supabase.rpc("start_quiz_session", { _session_id: session.id });
    if (error) toast.error(error.message);
  }
  return (
    <div className="grid gap-6 md:grid-cols-[1fr,1fr]">
      <Card className="bg-gradient-to-br from-primary/10 to-transparent">
        <CardHeader>
          <CardTitle>{tr("เชิญเข้าร่วม")}</CardTitle>
        </CardHeader>
        <CardContent className="text-center space-y-4">
          <div className="bg-white p-4 rounded-xl inline-block">
            <QRCodeSVG value={joinUrl} size={180} />
          </div>
          <div>
            <p className="text-xs text-muted-foreground">{tr("หรือใช้รหัส")}</p>
            <p className="font-mono text-5xl font-bold tracking-widest">{session.join_code}</p>
            <p className="text-xs text-muted-foreground mt-1">{tr("เข้าที่ /quiz/join")}</p>
          </div>
        </CardContent>
      </Card>
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            <span>{tr("ผู้เข้าร่วม")}</span>
            <Badge>{participants.length}</Badge>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {participants.length === 0 && (
            <p className="text-sm text-muted-foreground">{tr("รอผู้เล่นเข้าร่วม...")}</p>
          )}
          <div className="grid grid-cols-2 gap-2">
            {participants.map((p: any) => (
              <div key={p.id} className="px-3 py-2 rounded-md bg-muted/50 text-sm truncate">
                {p.display_name}
              </div>
            ))}
          </div>
          {isHost && (
            <Button
              className="w-full mt-4"
              size="lg"
              onClick={start}
              disabled={participants.length === 0}
            >
              <Play className="size-4 mr-2" /> เริ่มควิซ
            </Button>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

function Playing({ session, question, totalQuestions, isHost, userId }: any) {
  const [answered, setAnswered] = useState<number | null>(null);
  const [result, setResult] = useState<{ correct: boolean; score: number } | null>(null);
  const startedAt = useMemo(
    () => new Date(session.question_started_at).getTime(),
    [session.question_started_at],
  );
  const limitMs = question.time_limit_seconds * 1000;
  const [now, setNow] = useState(Date.now());
  useEffect(() => {
    const t = setInterval(() => setNow(Date.now()), 200);
    return () => clearInterval(t);
  }, []);
  useEffect(() => {
    setAnswered(null);
    setResult(null);
  }, [question.id]);

  const remaining = Math.max(0, limitMs - (now - startedAt));
  const pct = (remaining / limitMs) * 100;
  const timeUp = remaining === 0;
  const revealed = session.status === "question_revealed" || timeUp;

  const { data: answers } = useQuery({
    queryKey: ["quiz-answers", session.id, question.id],
    queryFn: async () =>
      (
        await supabase
          .from("quiz_answers")
          .select("answer_idx, is_correct, user_id")
          .eq("question_id", question.id)
      ).data ?? [],
    refetchInterval: 1500,
  });

  async function pick(idx: number) {
    if (answered !== null || timeUp || isHost) return;
    setAnswered(idx);
    try {
      const { data, error } = await supabase.rpc("submit_quiz_answer", {
        _question_id: question.id,
        _answer_idx: idx,
      });
      if (error) throw error;
      const r = data as any;
      setResult({ correct: r.is_correct, score: r.score });
    } catch (e: any) {
      toast.error(e.message);
      setAnswered(null);
    }
  }

  async function reveal() {
    await supabase.rpc("reveal_quiz_question", { _session_id: session.id });
  }
  async function next() {
    const { data, error } = await supabase.rpc("next_quiz_question", { _session_id: session.id });
    if (error) toast.error(error.message);
    if ((data as any)?.finished) {
      await supabase.rpc("finish_quiz_session", { _session_id: session.id });
    }
  }

  const counts = (question.options as string[]).map(
    (_, i) => answers?.filter((a) => a.answer_idx === i).length ?? 0,
  );
  const totalAnswered = answers?.length ?? 0;
  const maxCount = Math.max(1, ...counts);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Badge variant="outline">
          ข้อ {question.idx + 1} / {totalQuestions}
        </Badge>
        <Badge variant="secondary" className="font-mono">
          {Math.ceil(remaining / 1000)}s
        </Badge>
      </div>
      <Progress value={pct} className="h-2" />

      <Card>
        <CardHeader>
          <CardTitle className="text-2xl text-center">{question.question}</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid sm:grid-cols-2 gap-3">
            {(question.options as string[]).map((opt, i) => {
              const isMine = answered === i;
              const isCorrect = revealed && i === question.correct_idx;
              const isWrongPick = revealed && isMine && i !== question.correct_idx;
              const heightStyle = isHost ? { height: `${40 + (counts[i] / maxCount) * 80}px` } : {};
              return (
                <button
                  key={i}
                  onClick={() => pick(i)}
                  disabled={isHost || answered !== null || timeUp}
                  style={heightStyle}
                  className={`relative text-white font-medium text-lg p-4 rounded-xl border border-white/20 transition-all flex items-center gap-3
                    ${OPTION_COLORS[i % 4]}
                    ${answered !== null && !isMine ? "opacity-50" : ""}
                    ${isMine ? "ring-4 ring-offset-2 ring-primary" : ""}
                    ${isCorrect ? "ring-4 ring-offset-2 ring-green-400" : ""}
                    ${isWrongPick ? "opacity-60" : ""}
                    disabled:cursor-not-allowed`}
                >
                  <span className="text-2xl">{OPTION_SHAPES[i % 4]}</span>
                  <span className="flex-1 text-left">{opt}</span>
                  {isHost && (
                    <Badge variant="secondary" className="text-foreground">
                      {counts[i]}
                    </Badge>
                  )}
                  {isCorrect && <Check className="size-6" />}
                  {isWrongPick && <X className="size-6" />}
                </button>
              );
            })}
          </div>

          {!isHost && result && (
            <div
              className={`mt-4 p-4 rounded-xl text-center ${result.correct ? "bg-green-100 text-green-900" : "bg-red-100 text-red-900"}`}
            >
              <p className="font-bold text-xl">
                {result.correct
                  ? `🎉 ${tr("ถูกต้อง")}! +${result.score} ${tr("คะแนน")}`
                  : `❌ ${tr("ผิด")}`}
              </p>
            </div>
          )}
          {!isHost && answered === null && timeUp && (
            <p className="text-center mt-4 text-sm text-muted-foreground">{tr("หมดเวลา")}</p>
          )}

          {isHost && (
            <div className="mt-4 flex items-center justify-between gap-2">
              <p className="text-sm text-muted-foreground">
                {tr("ตอบแล้ว")}: {totalAnswered}
              </p>
              <div className="flex gap-2">
                {!revealed && (
                  <Button variant="outline" onClick={reveal}>
                    {tr("เฉลย")}
                  </Button>
                )}
                <Button onClick={next}>
                  {question.idx + 1 === totalQuestions ? (
                    tr("จบควิซ")
                  ) : (
                    <>
                      {tr("ข้อถัดไป")}
                      <ChevronRight className="size-4 ml-1" />
                    </>
                  )}
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

function Finished({ participants, isHost, sessionId }: any) {
  return (
    <div className="space-y-6">
      <div className="text-center space-y-2">
        <Trophy className="size-16 mx-auto text-amber-500" />
        <h2 className="font-display text-3xl">{tr("ผลควิซ")}</h2>
      </div>
      <Card>
        <CardContent className="p-4 space-y-2">
          {participants.map((p: any, i: number) => {
            const icon =
              i === 0 ? (
                <Crown className="size-5 text-amber-500" />
              ) : i === 1 ? (
                <Medal className="size-5 text-slate-400" />
              ) : i === 2 ? (
                <Medal className="size-5 text-orange-400" />
              ) : (
                <span className="w-5 text-center text-muted-foreground">{i + 1}</span>
              );
            return (
              <div
                key={p.id}
                className={`flex items-center justify-between p-3 rounded-lg ${i < 3 ? "bg-gradient-to-r from-primary/10 to-transparent" : "bg-muted/30"}`}
              >
                <div className="flex items-center gap-3">
                  {icon}
                  <span className="font-medium">{p.display_name}</span>
                </div>
                <Badge variant="outline" className="gap-1">
                  <Zap className="size-3" />
                  {p.total_score}
                </Badge>
              </div>
            );
          })}
          {participants.length === 0 && (
            <p className="text-center text-sm text-muted-foreground py-6">
              {tr("ไม่มีผู้เข้าร่วม")}
            </p>
          )}
        </CardContent>
      </Card>
      <Button variant="outline" asChild className="w-full">
        <Link to="/dashboard">{tr("กลับ Dashboard")}</Link>
      </Button>
    </div>
  );
}

import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/use-auth";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Plus, Trash2, Loader2, Sparkles } from "lucide-react";

import { tr } from "@/i18n";
export const Route = createFileRoute("/_authenticated/quiz/new")({
  validateSearch: (s: Record<string, unknown>) => ({ classroom: (s.classroom as string) ?? "" }),
  component: NewQuizPage,
});

type DraftQ = {
  question: string;
  options: string[];
  correct_idx: number;
  time_limit_seconds: number;
  points: number;
};

function emptyQ(): DraftQ {
  return {
    question: "",
    options: ["", "", "", ""],
    correct_idx: 0,
    time_limit_seconds: 20,
    points: 1000,
  };
}

function NewQuizPage() {
  const { user } = useAuth();
  const nav = useNavigate();
  const { classroom } = Route.useSearch();
  const [title, setTitle] = useState("");
  const [topic, setTopic] = useState("");
  const [questions, setQuestions] = useState<DraftQ[]>([emptyQ()]);
  const [generating, setGenerating] = useState(false);
  const [saving, setSaving] = useState(false);

  function update(i: number, patch: Partial<DraftQ>) {
    setQuestions((qs) => qs.map((q, idx) => (idx === i ? { ...q, ...patch } : q)));
  }
  function updateOption(i: number, oi: number, v: string) {
    setQuestions((qs) =>
      qs.map((q, idx) =>
        idx === i ? { ...q, options: q.options.map((o, j) => (j === oi ? v : o)) } : q,
      ),
    );
  }

  async function generateWithAI() {
    if (!topic.trim()) {
      toast.error(tr("กรอกหัวข้อก่อน"));
      return;
    }
    setGenerating(true);
    try {
      const { data, error } = await supabase.functions.invoke("generate-quest", {
        body: { topic, count: 5, multiple_choice: true },
      });
      if (error) throw error;
      const gen = (data as any)?.questions;
      if (Array.isArray(gen) && gen.length) {
        const mapped: DraftQ[] = gen.slice(0, 10).map((g: any) => ({
          question: g.question ?? "",
          options:
            Array.isArray(g.options) && g.options.length >= 2
              ? g.options.slice(0, 4).concat(Array(4).fill("")).slice(0, 4)
              : ["", "", "", ""],
          correct_idx: typeof g.correct_idx === "number" ? g.correct_idx : 0,
          time_limit_seconds: 20,
          points: 1000,
        }));
        setQuestions(mapped);
        if (!title) setTitle(topic);
        toast.success(`สร้าง ${mapped.length} ข้อแล้ว ตรวจทานก่อนบันทึก`);
      } else {
        toast.error(tr("AI ไม่คืนคำถามที่ใช้ได้ ลองอีกครั้ง"));
      }
    } catch (e: any) {
      toast.error(e.message ?? tr("AI ล้มเหลว"));
    } finally {
      setGenerating(false);
    }
  }

  async function save() {
    if (!classroom) {
      toast.error(tr("ไม่พบห้องเรียน"));
      return;
    }
    if (!title.trim()) {
      toast.error(tr("ใส่ชื่อควิซ"));
      return;
    }
    const valid = questions.filter(
      (q) => q.question.trim() && q.options.filter((o) => o.trim()).length >= 2,
    );
    if (valid.length === 0) {
      toast.error(tr("ต้องมีคำถามอย่างน้อย 1 ข้อ (มีตัวเลือก ≥2)"));
      return;
    }
    setSaving(true);
    try {
      const { data: s, error } = await supabase
        .from("quiz_sessions")
        .insert({
          classroom_id: classroom,
          host_id: user!.id,
          title,
        })
        .select()
        .single();
      if (error) throw error;
      const rows = valid.map((q, i) => ({
        session_id: s.id,
        idx: i,
        question: q.question,
        options: q.options.filter((o) => o.trim()),
        correct_idx: Math.min(q.correct_idx, q.options.filter((o) => o.trim()).length - 1),
        time_limit_seconds: q.time_limit_seconds,
        points: q.points,
      }));
      const { error: e2 } = await supabase.from("quiz_questions").insert(rows);
      if (e2) throw e2;
      toast.success(tr("สร้างควิซแล้ว"));
      nav({ to: "/quiz/$sessionId", params: { sessionId: s.id } });
    } catch (e: any) {
      toast.error(e.message);
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="mx-auto max-w-3xl p-6 lg:p-10 space-y-6">
      <header>
        <h1 className="font-display text-3xl">{tr("สร้าง Live Quiz")}</h1>
        <p className="text-muted-foreground mt-1">
          {tr("นักเรียนเข้าร่วมด้วยรหัส 6 หลัก ตอบเร็วได้คะแนนเยอะ")}
        </p>
      </header>

      <Card>
        <CardHeader>
          <CardTitle className="text-base">{tr("ข้อมูลควิซ")}</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="space-y-1.5">
            <Label>{tr("ชื่อควิซ")}</Label>
            <Input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder={tr("เช่น ทบทวนบทที่ 3")}
            />
          </div>
          <div className="space-y-1.5">
            <Label>{tr("สร้างจาก AI (ไม่บังคับ)")}</Label>
            <div className="flex gap-2">
              <Input
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                placeholder={tr("หัวข้อ เช่น สมการกำลังสอง")}
              />
              <Button
                type="button"
                variant="outline"
                onClick={generateWithAI}
                disabled={generating}
              >
                {generating ? (
                  <Loader2 className="size-4 animate-spin" />
                ) : (
                  <Sparkles className="size-4" />
                )}
                AI สร้าง 5 ข้อ
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="space-y-4">
        {questions.map((q, i) => (
          <Card key={i}>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm">ข้อ {i + 1}</CardTitle>
              {questions.length > 1 && (
                <Button
                  size="icon"
                  variant="ghost"
                  onClick={() => setQuestions((qs) => qs.filter((_, j) => j !== i))}
                >
                  <Trash2 className="size-4" />
                </Button>
              )}
            </CardHeader>
            <CardContent className="space-y-3">
              <Textarea
                rows={2}
                value={q.question}
                placeholder={tr("คำถาม")}
                onChange={(e) => update(i, { question: e.target.value })}
              />
              <div className="grid sm:grid-cols-2 gap-2">
                {q.options.map((opt, oi) => (
                  <label
                    key={oi}
                    className={`flex items-center gap-2 p-2 rounded-md border cursor-pointer ${q.correct_idx === oi ? "border-green-500 bg-green-50" : "border-input"}`}
                  >
                    <input
                      type="radio"
                      name={`correct-${i}`}
                      checked={q.correct_idx === oi}
                      onChange={() => update(i, { correct_idx: oi })}
                    />
                    <Input
                      value={opt}
                      onChange={(e) => updateOption(i, oi, e.target.value)}
                      placeholder={`ตัวเลือก ${oi + 1}`}
                      className="flex-1 border-0 shadow-none focus-visible:ring-0 p-0 h-6"
                    />
                  </label>
                ))}
              </div>
              <div className="flex gap-3 text-sm">
                <label className="flex items-center gap-2">
                  เวลา (วิ)
                  <Input
                    type="number"
                    min={5}
                    max={120}
                    value={q.time_limit_seconds}
                    onChange={(e) => update(i, { time_limit_seconds: +e.target.value || 20 })}
                    className="w-20"
                  />
                </label>
                <label className="flex items-center gap-2">
                  คะแนน
                  <Input
                    type="number"
                    min={100}
                    max={2000}
                    step={100}
                    value={q.points}
                    onChange={(e) => update(i, { points: +e.target.value || 1000 })}
                    className="w-24"
                  />
                </label>
              </div>
            </CardContent>
          </Card>
        ))}
        <Button
          variant="outline"
          className="w-full"
          onClick={() => setQuestions((qs) => [...qs, emptyQ()])}
        >
          <Plus className="size-4 mr-1" />
          เพิ่มคำถาม
        </Button>
      </div>

      <div className="sticky bottom-4 flex justify-end gap-2">
        <Button
          variant="outline"
          onClick={() => nav({ to: "/classrooms/$id", params: { id: classroom } })}
        >
          {tr("ยกเลิก")}
        </Button>
        <Button onClick={save} disabled={saving} size="lg">
          {saving ? <Loader2 className="size-4 mr-1 animate-spin" /> : null}บันทึก & ไปที่ห้องรอ
        </Button>
      </div>
    </div>
  );
}

import { createFileRoute } from "@tanstack/react-router";
