import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { KeyRound, Loader2 } from "lucide-react";
import { LanguageSwitcher } from "@/components/language-switcher";

import { tr } from "@/i18n";
export const Route = createFileRoute("/checkin")({
  validateSearch: (s: Record<string, unknown>) => ({ code: (s.code as string) ?? "" }),
  component: CheckInPage,
});

function CheckInPage() {
  const nav = useNavigate();
  const { code: initial } = Route.useSearch();
  const [code, setCode] = useState(initial);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data }) => {
      const redirect = initial ? `/checkin?code=${encodeURIComponent(initial)}` : "/checkin";
      if (!data.session) nav({ to: "/login", search: { redirect } as any });
    });
  }, [initial, nav]);

  async function submit(e: React.FormEvent) {
    e.preventDefault();
    if (!code.trim()) return;
    setLoading(true);
    try {
      const { data, error } = await supabase.rpc("self_check_in", {
        p_code: code.trim().toUpperCase(),
      });
      if (error) throw error;
      const row = Array.isArray(data) ? (data as any[])[0] : (data as any);
      const status = row?.status;
      const xp = status === "late" ? 5 : 15;
      const gold = status === "late" ? 2 : 5;
      toast.success(
        (status === "late" ? tr("เช็กชื่อสำเร็จ (สาย)") : tr("เช็กชื่อสำเร็จ ✅")) +
          ` +${xp} XP, +${gold} ${tr("ทอง")}`,
      );
      setTimeout(() => nav({ to: "/dashboard" }), 1500);
    } catch (e: any) {
      toast.error(e.message ?? tr("เช็กชื่อไม่สำเร็จ"));
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen grid place-items-center p-6 bg-gradient-to-br from-primary/5 to-background relative">
      <div className="absolute top-3 right-3">
        <LanguageSwitcher />
      </div>
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <div className="size-14 mx-auto rounded-xl bg-primary/15 grid place-items-center mb-2">
            <KeyRound className="size-7 text-primary" />
          </div>
          <CardTitle className="font-display text-2xl">{tr("เช็กชื่อเข้าเรียน")}</CardTitle>
          <p className="text-sm text-muted-foreground">{tr("กรอกรหัส 6 หลักจากครู")}</p>
        </CardHeader>
        <CardContent>
          <form onSubmit={submit} className="space-y-4">
            <div className="space-y-1.5">
              <Label htmlFor="checkin-code">{tr("รหัสเช็กชื่อ")}</Label>
              <Input
                id="checkin-code"
                value={code}
                onChange={(e) => setCode(e.target.value.toUpperCase())}
                maxLength={6}
                placeholder="ABC123"
                className="text-center text-2xl font-mono tracking-widest h-14"
                autoFocus
              />
            </div>
            <Button
              type="submit"
              className="w-full"
              size="lg"
              disabled={loading || code.length < 6}
            >
              {loading ? <Loader2 className="size-4 animate-spin mr-2" /> : null}
              เช็กชื่อ
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

// AI grades student answers to a quest
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

const cors = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response(null, { headers: cors });
  try {
    // Require authentication — handler returns answer-key-derived feedback
    // and must not be callable anonymously.
    const authHeader = req.headers.get("Authorization") ?? "";
    const supa = createClient(Deno.env.get("SUPABASE_URL")!, Deno.env.get("SUPABASE_ANON_KEY")!, {
      global: { headers: { Authorization: authHeader } },
    });
    const {
      data: { user },
      error: authErr,
    } = await supa.auth.getUser();
    if (authErr || !user) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    const body = await req.json();
    const { quest_id, answers, only_index } = body;
    const apiKey = Deno.env.get("LOVABLE_API_KEY");
    if (!apiKey) throw new Error("LOVABLE_API_KEY missing");
    if (!quest_id || !Array.isArray(answers)) throw new Error("invalid input");

    // Fetch authoritative questions (with answer keys) server-side using service role
    const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
    const SERVICE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const qRes = await fetch(`${SUPABASE_URL}/rest/v1/rpc/get_quest_for_grading`, {
      method: "POST",
      headers: {
        apikey: SERVICE_KEY,
        Authorization: `Bearer ${SERVICE_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ _quest_id: quest_id }),
    });
    if (!qRes.ok) throw new Error(`fetch quest failed: ${qRes.status}`);
    const allQuestions = await qRes.json();
    if (!Array.isArray(allQuestions)) throw new Error("quest not found");

    // If only_index is given, grade just that one question (keep idx aligned with full list)
    const targetIndices: number[] =
      typeof only_index === "number" ? [only_index] : allQuestions.map((_: any, i: number) => i);

    const system = `คุณคือ AI ครูใจดีที่ตรวจคำตอบนักเรียนภาษาไทยอย่างยุติธรรมและให้คะแนนแบบ "บางส่วน" (partial credit)

หลักการให้คะแนน (สำคัญมาก):
- อย่าให้ 0 ถ้าคำตอบมีความเกี่ยวข้องบ้าง ให้คะแนนตามระดับความใกล้เคียง/ความเข้าใจ
- ตรง 100% = เต็ม / ใกล้เคียงมาก = 80-90% / เข้าใจหลักแต่ไม่ครบ = 50-70% / เกี่ยวข้องเล็กน้อย = 20-40% / ไม่เกี่ยวเลย/ว่างเปล่า = 0
- ยอมรับคำพ้องความหมาย คำใกล้เคียง การสะกดผิดเล็กน้อย และคำตอบที่กว้างกว่าหรือแคบกว่าเฉลย
- เช่น ถ้าเฉลยคือ "โปรแกรมออกแบบกราฟิก" คำตอบ "โปรแกรมทำภาพ" / "โปรแกรมนำเสนอ" / "ใช้ทำโปสเตอร์" ควรได้คะแนนบางส่วน ไม่ใช่ 0
- คะแนน (score) ต้องเป็นจำนวนเต็ม 0 ถึง max_points
- correct = true เฉพาะเมื่อ score >= 80% ของ max_points
- feedback สั้น เป็นกำลังใจ บอกสิ่งที่ดี + สิ่งที่เติมได้`;

    const payload = allQuestions
      .filter((_: any, i: number) => targetIndices.includes(i))
      .map((q: any) => {
        const i = allQuestions.indexOf(q);
        return {
          idx: i,
          question: q.question,
          expected: q.expected_answer,
          keywords: q.keywords ?? [],
          max_points: q.points ?? Math.floor(100 / allQuestions.length),
          student_answer: answers[i] ?? "",
        };
      });

    const res = await fetch("https://ai.gateway.lovable.dev/v1/chat/completions", {
      method: "POST",
      headers: { Authorization: `Bearer ${apiKey}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "google/gemini-2.5-flash",
        messages: [
          { role: "system", content: system },
          { role: "user", content: `ตรวจคำตอบ:\n${JSON.stringify(payload, null, 2)}` },
        ],
        tools: [
          {
            type: "function",
            function: {
              name: "grade",
              description: "Submit grading results",
              parameters: {
                type: "object",
                properties: {
                  results: {
                    type: "array",
                    items: {
                      type: "object",
                      properties: {
                        idx: { type: "number" },
                        score: { type: "number" },
                        max_score: { type: "number" },
                        correct: { type: "boolean" },
                        feedback: { type: "string" },
                      },
                      required: ["idx", "score", "max_score", "correct", "feedback"],
                      additionalProperties: false,
                    },
                  },
                  overall_feedback: { type: "string" },
                },
                required: ["results", "overall_feedback"],
                additionalProperties: false,
              },
            },
          },
        ],
        tool_choice: { type: "function", function: { name: "grade" } },
      }),
    });
    if (res.status === 429)
      return new Response(JSON.stringify({ error: "rate_limit" }), {
        status: 429,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    if (res.status === 402)
      return new Response(JSON.stringify({ error: "credits" }), {
        status: 402,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    if (!res.ok)
      return new Response(JSON.stringify({ error: await res.text() }), {
        status: res.status,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    const j = await res.json();
    const args = j.choices?.[0]?.message?.tool_calls?.[0]?.function?.arguments;
    const parsed = args ? JSON.parse(args) : { results: [], overall_feedback: "" };
    const total = parsed.results.reduce((s: number, r: any) => s + (r.score ?? 0), 0);
    const max = parsed.results.reduce((s: number, r: any) => s + (r.max_score ?? 0), 0);
    return new Response(JSON.stringify({ ...parsed, total_score: total, max_score: max }), {
      headers: { ...cors, "Content-Type": "application/json" },
    });
  } catch (e) {
    return new Response(JSON.stringify({ error: String(e) }), {
      status: 500,
      headers: { ...cors, "Content-Type": "application/json" },
    });
  }
});

// Personal AI tutor - scoped to lesson contents from student's classrooms
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

const cors = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response(null, { headers: cors });
  try {
    const { messages, classroom_id } = await req.json();
    const apiKey = Deno.env.get("LOVABLE_API_KEY");
    if (!apiKey) throw new Error("LOVABLE_API_KEY missing");

    const supaUrl = Deno.env.get("SUPABASE_URL")!;
    const supaKey = Deno.env.get("SUPABASE_ANON_KEY")!;
    const authHeader = req.headers.get("Authorization") ?? "";
    const supa = createClient(supaUrl, supaKey, {
      global: { headers: { Authorization: authHeader } },
    });

    // Require an authenticated user before forwarding to the AI gateway.
    const {
      data: { user },
      error: authErr,
    } = await supa.auth.getUser();
    if (authErr || !user) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    // Fetch lesson contents from classrooms the user is in (RLS enforces)
    let q = supa
      .from("lesson_contents")
      .select("topic, content, lesson_date, classroom_id")
      .order("lesson_date", { ascending: false })
      .limit(20);
    if (classroom_id) q = q.eq("classroom_id", classroom_id);
    const { data: lessons } = await q;

    const scope = (lessons ?? [])
      .map((l: any) => `[${l.lesson_date}] ${l.topic}\n${l.content}`)
      .join("\n\n---\n\n");

    const system = `คุณคือ Scholar Tutor ครูส่วนตัวของนักเรียน
**กฎสำคัญ:**
- ตอบคำถามได้เฉพาะหัวข้อที่อยู่ใน "เนื้อหาที่ครูสอน" ด้านล่างเท่านั้น
- คุณสามารถอธิบายเพิ่ม ยกตัวอย่าง ถามกลับ หรือสร้างโจทย์ฝึกในขอบเขตเดียวกันได้
- ถ้านักเรียนถามเรื่องนอกขอบเขต ให้บอกสุภาพว่า "ครูยังไม่ได้สอนเรื่องนี้ ลองถามอาจารย์หรือรอบทเรียนถัดไปนะ"
- ตอบเป็นภาษาไทย กระชับ เป็นมิตร เหมาะกับเด็ก
- ไม่เฉลยคำตอบของ Quest โดยตรง แต่ช่วยอธิบายแนวคิด

**เนื้อหาที่ครูสอน:**
${scope || "(ยังไม่มีบทเรียน — แจ้งนักเรียนว่ายังไม่มีเนื้อหาให้สอบถาม)"}`;

    const res = await fetch("https://ai.gateway.lovable.dev/v1/chat/completions", {
      method: "POST",
      headers: { Authorization: `Bearer ${apiKey}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "google/gemini-2.5-flash",
        messages: [{ role: "system", content: system }, ...(messages ?? [])],
        stream: true,
      }),
    });
    if (res.status === 429)
      return new Response(JSON.stringify({ error: "rate_limit" }), {
        status: 429,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    if (res.status === 402)
      return new Response(JSON.stringify({ error: "credits" }), {
        status: 402,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    if (!res.ok)
      return new Response(JSON.stringify({ error: await res.text() }), {
        status: res.status,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    return new Response(res.body, {
      headers: { ...cors, "Content-Type": "text/event-stream", "Cache-Control": "no-cache" },
    });
  } catch (e) {
    return new Response(JSON.stringify({ error: String(e) }), {
      status: 500,
      headers: { ...cors, "Content-Type": "application/json" },
    });
  }
});
